CREATE OR REPLACE FUNCTION public.admin_delete_user(p_user_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    deleted_user jsonb;
    is_admin boolean;
BEGIN
    -- Security: Only admins can call this
    SELECT role = 'admin' INTO is_admin
    FROM profiles WHERE id = auth.uid();
    
    IF NOT is_admin THEN
        RAISE EXCEPTION 'Unauthorized: Admin role required';
    END IF;
    
    -- Prevent self-deletion
    IF p_user_id = auth.uid() THEN
        RAISE EXCEPTION 'Cannot delete your own account';
    END IF;
    
    -- Get user info before deletion (for confirmation/logging)
    SELECT jsonb_build_object(
        'id', id,
        'username', username,
        'role', role,
        'created_at', created_at,
        'deleted_at', now()
    ) INTO deleted_user
    FROM profiles WHERE id = p_user_id;
    
    -- Check if user exists
    IF deleted_user IS NULL THEN
        RAISE EXCEPTION 'User not found';
    END IF;
    
    -- Delete from profiles table
    -- Foreign key CASCADE will handle:
    --   - playlists (user_id FK)
    --   - playlist_items (via playlists cascade)
    --   - watch_party (created_by FK)  
    --   - watch_party_members (user_id FK)
    --   - playlist_likes (user_id FK)
    --   - follows (follower_id/following_id FK)
    DELETE FROM profiles WHERE id = p_user_id;
    
    -- Return deleted user info for audit logging
    RETURN deleted_user;
END;
$function$

CREATE OR REPLACE FUNCTION public.admin_disable_guest_link(p_link_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT public.is_admin_user(auth.uid()) THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  UPDATE public.guest_access_links
  SET status = 'disabled'
  WHERE id = p_link_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Guest access link not found';
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.admin_extend_guest_access(p_user_id uuid, p_expires_at timestamp with time zone)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  target_link_id uuid;
BEGIN
  IF NOT public.is_admin_user(auth.uid()) THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  IF p_expires_at IS NULL OR p_expires_at <= now() THEN
    RAISE EXCEPTION 'Guest expiry must be in the future';
  END IF;

  UPDATE public.profiles
  SET guest_expires_at = p_expires_at
  WHERE id = p_user_id
    AND account_kind = 'guest'
  RETURNING guest_link_id INTO target_link_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Active guest account not found';
  END IF;

  IF target_link_id IS NOT NULL THEN
    UPDATE public.guest_access_links
    SET expires_at = GREATEST(expires_at, p_expires_at)
    WHERE id = target_link_id;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.admin_update_user_role(p_user_id uuid, p_new_role text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_role text;
BEGIN
  SELECT profiles.role
  INTO requester_role
  FROM public.profiles
  WHERE profiles.id = auth.uid();

  IF requester_role IS DISTINCT FROM 'admin' THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  IF p_new_role NOT IN ('user', 'admin', 'moderator') THEN
    RAISE EXCEPTION 'Invalid role';
  END IF;

  IF p_user_id = auth.uid() AND p_new_role <> 'admin' THEN
    RAISE EXCEPTION 'Cannot change your own admin role';
  END IF;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET role = p_new_role
  WHERE id = p_user_id;
END;
$function$

