CREATE OR REPLACE FUNCTION public.build_unique_username(p_base text)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  normalized_base text;
  candidate text;
  suffix integer := 0;
BEGIN
  normalized_base := lower(regexp_replace(COALESCE(p_base, 'guest'), '[^a-zA-Z0-9]+', '_', 'g'));
  normalized_base := regexp_replace(normalized_base, '^_+|_+$', '', 'g');

  IF normalized_base = '' THEN
    normalized_base := 'guest';
  END IF;

  candidate := left(normalized_base, 48);

  WHILE EXISTS (
    SELECT 1
    FROM public.profiles
    WHERE username = candidate
  ) LOOP
    suffix := suffix + 1;
    candidate := left(normalized_base, GREATEST(1, 48 - length(suffix::text) - 1)) || '_' || suffix::text;
  END LOOP;

  RETURN candidate;
END;
$function$

CREATE OR REPLACE FUNCTION public.calculate_taste_compatibility(user_a uuid, user_b uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    genres_a JSONB;
    genres_b JSONB;
    total_score INTEGER := 0;
    shared_genres TEXT[] := ARRAY[]::TEXT[];
    key TEXT;
    val_a INTEGER;
    val_b INTEGER;
BEGIN
    SELECT stats->'genre_counts' INTO genres_a FROM public.profiles WHERE id = user_a;
    SELECT stats->'genre_counts' INTO genres_b FROM public.profiles WHERE id = user_b;
    
    IF genres_a IS NULL OR genres_b IS NULL THEN
        RETURN jsonb_build_object('score', 0, 'shared', ARRAY[]::TEXT[], 'message', 'Not enough data');
    END IF;

    FOR key IN SELECT jsonb_object_keys(genres_a) LOOP
        IF genres_b ? key THEN
            val_a := (genres_a->>key)::INTEGER;
            val_b := (genres_b->>key)::INTEGER;
            total_score := total_score + (LEAST(val_a, val_b) * 5);
            shared_genres := array_append(shared_genres, key);
        END IF;
    END LOOP;
    
    IF total_score > 100 THEN total_score := 100; END IF;
    RETURN jsonb_build_object('score', total_score, 'shared', shared_genres);
END;
$function$

CREATE OR REPLACE FUNCTION public.check_registration_enabled()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    is_enabled text;
BEGIN
    -- Anonymous guest sessions should still be allowed even when public
    -- registration is disabled for standard users.
    IF COALESCE(NEW.is_anonymous, false) THEN
        RETURN NEW;
    END IF;

    SELECT value INTO is_enabled
    FROM public.app_settings
    WHERE key = 'registration_enabled';

    IF is_enabled = 'false' THEN
        RAISE EXCEPTION 'New user registration is currently disabled. Please contact an administrator.'
            USING HINT = 'Registration can be enabled by an admin in the dashboard';
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.cleanup_unclaimed_guest_session()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  requester_profile public.profiles%ROWTYPE;
  is_anonymous_session boolean := COALESCE((auth.jwt() ->> 'is_anonymous')::boolean, false);
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF NOT is_anonymous_session THEN
    RAISE EXCEPTION 'Only anonymous sessions can be cleaned up';
  END IF;

  SELECT *
  INTO requester_profile
  FROM public.profiles
  WHERE id = requester_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  IF requester_profile.account_kind = 'guest'
     OR requester_profile.guest_link_id IS NOT NULL
     OR requester_profile.guest_secured_at IS NOT NULL THEN
    RAISE EXCEPTION 'Claimed guest accounts cannot be cleaned up through this RPC';
  END IF;

  DELETE FROM auth.users
  WHERE id = requester_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.create_movie_request_secure(p_tmdb_id text, p_media_type text, p_title text, p_poster_path text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, tmdb_id text, media_type text, title text, poster_path text, status text, created_by uuid, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  safe_tmdb_id text := NULLIF(btrim(COALESCE(p_tmdb_id, '')), '');
  safe_media_type text := NULLIF(btrim(COALESCE(p_media_type, '')), '');
  safe_title text := NULLIF(btrim(COALESCE(p_title, '')), '');
  safe_poster_path text := NULLIF(btrim(COALESCE(p_poster_path, '')), '');
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Must be logged in to request';
  END IF;

  IF safe_tmdb_id IS NULL OR safe_title IS NULL THEN
    RAISE EXCEPTION 'A title and TMDB id are required';
  END IF;

  IF safe_media_type NOT IN ('movie', 'tv') THEN
    RAISE EXCEPTION 'Invalid media type';
  END IF;

  IF length(safe_title) > 250 THEN
    RAISE EXCEPTION 'Title is too long';
  END IF;

  PERFORM public.enforce_community_rate_limit('create_request', 2, 300);

  RETURN QUERY
  INSERT INTO public.movie_requests (
    tmdb_id,
    media_type,
    title,
    poster_path,
    created_by
  )
  VALUES (
    safe_tmdb_id,
    safe_media_type,
    safe_title,
    safe_poster_path,
    requester_id
  )
  RETURNING
    movie_requests.id,
    movie_requests.tmdb_id,
    movie_requests.media_type,
    movie_requests.title,
    movie_requests.poster_path,
    movie_requests.status,
    movie_requests.created_by,
    movie_requests.created_at,
    movie_requests.updated_at;
EXCEPTION
  WHEN unique_violation THEN
    RAISE EXCEPTION 'This movie has already been requested!';
END;
$function$

CREATE OR REPLACE FUNCTION public.delete_direct_message(p_message_id uuid)
 RETURNS TABLE(conversation_id uuid, deleted_message_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  message_record public.direct_messages%ROWTYPE;
  replacement_message record;
  replacement_preview text;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO message_record
  FROM public.direct_messages
  WHERE id = p_message_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Message not found';
  END IF;

  IF message_record.sender_id <> requester_id THEN
    RAISE EXCEPTION 'Only the sender can unsend this message';
  END IF;

  DELETE FROM public.direct_messages
  WHERE id = p_message_id;

  DELETE FROM public.notifications
  WHERE type = 'direct_message'
    AND data ->> 'message_id' = p_message_id::text;

  SELECT
    message.id,
    message.sender_id,
    message.message_type,
    message.body,
    message.created_at
  INTO replacement_message
  FROM public.direct_messages AS message
  WHERE message.conversation_id = message_record.conversation_id
  ORDER BY message.created_at DESC
  LIMIT 1;

  replacement_preview := CASE
    WHEN replacement_message.id IS NULL THEN NULL
    WHEN replacement_message.message_type = 'movie_share' AND replacement_message.body IS NOT NULL THEN LEFT(replacement_message.body, 120)
    WHEN replacement_message.message_type = 'movie_share' THEN 'Shared a title'
    ELSE LEFT(replacement_message.body, 120)
  END;

  UPDATE public.direct_conversations
  SET
    updated_at = COALESCE(replacement_message.created_at, now()),
    last_message_at = COALESCE(replacement_message.created_at, direct_conversations.created_at),
    last_message_preview = replacement_preview,
    last_message_sender_id = replacement_message.sender_id
  WHERE id = message_record.conversation_id;

  RETURN QUERY
  SELECT message_record.conversation_id, p_message_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.enforce_community_rate_limit(p_action text, p_max_count integer, p_window_seconds integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  current_count integer := 0;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_max_count < 1 OR p_window_seconds < 1 THEN
    RAISE EXCEPTION 'Invalid rate limit configuration';
  END IF;

  DELETE FROM public.community_rate_limits
  WHERE created_at < now() - interval '1 day';

  SELECT count(*)
  INTO current_count
  FROM public.community_rate_limits
  WHERE user_id = requester_id
    AND action = p_action
    AND created_at >= now() - make_interval(secs => p_window_seconds);

  IF current_count >= p_max_count THEN
    RAISE EXCEPTION 'Please wait before trying again.';
  END IF;

  INSERT INTO public.community_rate_limits (user_id, action)
  VALUES (requester_id, p_action);
END;
$function$

CREATE OR REPLACE FUNCTION public.get_private_watch_history(p_user_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  requester_role text;
  target_user_id uuid := COALESCE(p_user_id, requester_id);
  history jsonb;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF target_user_id IS DISTINCT FROM requester_id THEN
    SELECT profiles.role
    INTO requester_role
    FROM public.profiles
    WHERE profiles.id = requester_id;

    IF requester_role IS DISTINCT FROM 'admin' THEN
      RAISE EXCEPTION 'Admin access required';
    END IF;
  END IF;

  SELECT COALESCE(profile.watch_history, '{}'::jsonb)
  INTO history
  FROM public.profiles profile
  WHERE profile.id = target_user_id;

  RETURN COALESCE(history, '{}'::jsonb);
END;
$function$

CREATE OR REPLACE FUNCTION public.handle_reply_vote(p_reply_id uuid, p_vote integer)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  current_vote integer;
  new_total integer;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_vote NOT IN (1, -1) THEN
    RAISE EXCEPTION 'Invalid vote';
  END IF;

  PERFORM public.enforce_community_rate_limit('vote_reply', 10, 60);

  SELECT vote INTO current_vote
  FROM public.reply_votes
  WHERE reply_id = p_reply_id AND user_id = auth.uid();

  IF current_vote IS NOT NULL THEN
    IF current_vote = p_vote THEN
      RETURN (SELECT upvotes FROM public.request_replies WHERE id = p_reply_id);
    END IF;

    UPDATE public.reply_votes
    SET vote = p_vote
    WHERE reply_id = p_reply_id AND user_id = auth.uid();

    UPDATE public.request_replies
    SET upvotes = upvotes + (p_vote - current_vote)
    WHERE id = p_reply_id
    RETURNING upvotes INTO new_total;
  ELSE
    INSERT INTO public.reply_votes (reply_id, user_id, vote)
    VALUES (p_reply_id, auth.uid(), p_vote);

    UPDATE public.request_replies
    SET upvotes = upvotes + p_vote
    WHERE id = p_reply_id
    RETURNING upvotes INTO new_total;
  END IF;

  RETURN new_total;
END;
$function$

CREATE OR REPLACE FUNCTION public.heartbeat_view_session(p_session_id text, p_tmdb_id text, p_media_type text, p_season integer DEFAULT NULL::integer, p_episode integer DEFAULT NULL::integer, p_provider_id text DEFAULT NULL::text, p_title text DEFAULT NULL::text, p_genres text[] DEFAULT NULL::text[], p_heartbeat_seconds integer DEFAULT 30)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  current_user_id uuid;
  current_stats jsonb;
  session_record public.view_sessions%ROWTYPE;
  qualified_threshold integer;
  heartbeat_seconds integer;
  counted_key text;
  completion_count integer;
  genre_name text;
  previous_last_watched timestamptz;
  current_streak integer;
  days_since_last_watch integer;
  current_month text;
  today text;
  today_count integer;
BEGIN
  current_user_id := auth.uid();
  IF current_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_media_type NOT IN ('movie', 'tv') THEN
    RAISE EXCEPTION 'Invalid media type: %', p_media_type;
  END IF;

  heartbeat_seconds := GREATEST(15, LEAST(COALESCE(p_heartbeat_seconds, 30), 60));
  qualified_threshold := CASE
    WHEN p_media_type = 'movie' THEN 20 * 60
    ELSE 10 * 60
  END;

  SELECT stats
  INTO current_stats
  FROM public.profiles
  WHERE id = current_user_id
  FOR UPDATE;

  IF current_stats IS NULL THEN
    current_stats := '{}'::jsonb;
  END IF;

  IF current_stats->'genre_counts' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{genre_counts}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'streak_days' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{streak_days}', '0'::jsonb, true);
  END IF;
  IF current_stats->'max_streak' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{max_streak}', '0'::jsonb, true);
  END IF;
  IF current_stats->'total_movies' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{total_movies}', '0'::jsonb, true);
  END IF;
  IF current_stats->'total_shows' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{total_shows}', '0'::jsonb, true);
  END IF;
  IF current_stats->'monthly_watches' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{monthly_watches}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'rewatch_count' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{rewatch_count}', '0'::jsonb, true);
  END IF;
  IF current_stats->'binge_days' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{binge_days}', '0'::jsonb, true);
  END IF;
  IF current_stats->'daily_watch_count' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{daily_watch_count}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'title_rewatch_counts' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{title_rewatch_counts}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'wrapped_counted_titles' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{wrapped_counted_titles}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'wrapped_completed_units' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{wrapped_completed_units}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'past_years' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{past_years}', '{}'::jsonb, true);
  END IF;
  IF current_stats->'year' IS NULL THEN
    current_stats := jsonb_set(current_stats, '{year}', to_jsonb(extract(year from now())::int), true);
  END IF;

  IF COALESCE((current_stats->>'year')::int, extract(year from now())::int) < extract(year from now())::int THEN
    current_stats := jsonb_set(
      current_stats,
      array['past_years', (current_stats->>'year')],
      current_stats - 'past_years' - 'wrapped_counted_titles' - 'wrapped_completed_units',
      true
    );
    current_stats := jsonb_set(current_stats, '{total_movies}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{total_shows}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{streak_days}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{max_streak}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{genre_counts}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{monthly_watches}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{first_watch_of_year}', 'null'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{rewatch_count}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{binge_days}', '0'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{daily_watch_count}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{title_rewatch_counts}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{wrapped_counted_titles}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{wrapped_completed_units}', '{}'::jsonb, true);
    current_stats := jsonb_set(current_stats, '{year}', to_jsonb(extract(year from now())::int), true);
  END IF;

  INSERT INTO public.view_sessions (
    user_id, session_id, tmdb_id, media_type, season, episode, provider_id, title, genres,
    active_seconds, session_date, started_at, last_heartbeat_at, updated_at
  )
  VALUES (
    current_user_id, p_session_id, p_tmdb_id, p_media_type, p_season, p_episode,
    p_provider_id, p_title, COALESCE(to_jsonb(p_genres), '[]'::jsonb),
    heartbeat_seconds, current_date, now(), now(), now()
  )
  ON CONFLICT (user_id, session_id)
  DO UPDATE SET
    last_heartbeat_at = now(),
    updated_at = now(),
    provider_id = COALESCE(EXCLUDED.provider_id, public.view_sessions.provider_id),
    title = COALESCE(EXCLUDED.title, public.view_sessions.title),
    genres = CASE
      WHEN EXCLUDED.genres IS NULL OR EXCLUDED.genres = 'null'::jsonb OR EXCLUDED.genres = '[]'::jsonb
        THEN public.view_sessions.genres
      ELSE EXCLUDED.genres
    END,
    active_seconds = public.view_sessions.active_seconds + heartbeat_seconds;

  SELECT *
  INTO session_record
  FROM public.view_sessions
  WHERE user_id = current_user_id
    AND session_id = p_session_id
  FOR UPDATE;

  IF NOT session_record.is_qualified AND session_record.active_seconds >= qualified_threshold THEN
    UPDATE public.view_sessions
    SET
      is_qualified = true,
      qualified_at = now(),
      updated_at = now()
    WHERE id = session_record.id;

    counted_key := CASE
      WHEN p_media_type = 'movie' THEN format('movie:%s', p_tmdb_id)
      ELSE format('tv:%s:s%s:e%s', p_tmdb_id, COALESCE(p_season, 1), COALESCE(p_episode, 1))
    END;

    IF NOT (current_stats->'wrapped_counted_titles' ? counted_key) THEN
      IF p_media_type = 'movie' THEN
        current_stats := jsonb_set(current_stats, '{total_movies}', ((current_stats->>'total_movies')::int + 1)::text::jsonb, true);
      ELSE
        current_stats := jsonb_set(current_stats, '{total_shows}', ((current_stats->>'total_shows')::int + 1)::text::jsonb, true);
      END IF;

      IF jsonb_typeof(session_record.genres) = 'array' THEN
        FOR genre_name IN SELECT jsonb_array_elements_text(session_record.genres)
        LOOP
          current_stats := jsonb_set(
            current_stats,
            array['genre_counts', genre_name],
            (COALESCE((current_stats->'genre_counts'->>genre_name)::int, 0) + 1)::text::jsonb,
            true
          );
        END LOOP;
      END IF;

      current_stats := jsonb_set(current_stats, array['wrapped_counted_titles', counted_key], 'true'::jsonb, true);
    END IF;

    completion_count := COALESCE((current_stats->'wrapped_completed_units'->>counted_key)::int, 0);
    IF completion_count >= 1 THEN
      current_stats := jsonb_set(current_stats, '{rewatch_count}', ((current_stats->>'rewatch_count')::int + 1)::text::jsonb, true);
      current_stats := jsonb_set(
        current_stats,
        array['title_rewatch_counts', COALESCE(session_record.title, p_tmdb_id)],
        (COALESCE((current_stats->'title_rewatch_counts'->>COALESCE(session_record.title, p_tmdb_id))::int, 0) + 1)::text::jsonb,
        true
      );
    END IF;

    current_stats := jsonb_set(
      current_stats,
      array['wrapped_completed_units', counted_key],
      (completion_count + 1)::text::jsonb,
      true
    );

    current_month := to_char(now(), 'YYYY-MM');
    current_stats := jsonb_set(
      current_stats,
      array['monthly_watches', current_month],
      (COALESCE((current_stats->'monthly_watches'->>current_month)::int, 0) + 1)::text::jsonb,
      true
    );

    today := to_char(now(), 'YYYY-MM-DD');
    today_count := COALESCE((current_stats->'daily_watch_count'->>today)::int, 0) + 1;
    current_stats := jsonb_set(current_stats, array['daily_watch_count', today], today_count::text::jsonb, true);
    IF today_count = 3 THEN
      current_stats := jsonb_set(current_stats, '{binge_days}', ((current_stats->>'binge_days')::int + 1)::text::jsonb, true);
    END IF;

    previous_last_watched := (current_stats->>'last_watched')::timestamptz;
    current_streak := COALESCE((current_stats->>'streak_days')::int, 0);
    IF previous_last_watched IS NULL THEN
      current_streak := 1;
    ELSE
      days_since_last_watch := current_date - date(previous_last_watched);
      IF days_since_last_watch = 1 THEN
        current_streak := current_streak + 1;
      ELSIF days_since_last_watch > 1 THEN
        current_streak := 1;
      END IF;
    END IF;

    current_stats := jsonb_set(current_stats, '{streak_days}', current_streak::text::jsonb, true);
    current_stats := jsonb_set(current_stats, '{last_watched}', to_jsonb(now()), true);

    IF current_streak > COALESCE((current_stats->>'max_streak')::int, 0) THEN
      current_stats := jsonb_set(current_stats, '{max_streak}', current_streak::text::jsonb, true);
    END IF;

    IF current_stats->'first_watch_of_year' IS NULL
      OR COALESCE((current_stats->'first_watch_of_year'->>'year')::int, 0) < extract(year from now())::int THEN
      current_stats := jsonb_set(current_stats, '{first_watch_of_year}', jsonb_build_object(
        'tmdb_id', p_tmdb_id,
        'title', COALESCE(session_record.title, p_tmdb_id),
        'date', current_date::text,
        'type', p_media_type,
        'year', extract(year from now())::int
      ), true);
    END IF;

    PERFORM set_config('app.trusted_profile_write', 'on', true);

    UPDATE public.profiles
    SET
      stats = current_stats,
      last_seen_activity = now()
    WHERE id = current_user_id;
  END IF;
END;
$function$

