  GET DIAGNOSTICS updated_count = ROW_COUNT;

  UPDATE public.notifications
  SET is_read = true
  WHERE user_id = requester_id
    AND type = 'direct_message'
    AND is_read = false
    AND data ->> 'conversation_id' = p_conversation_id::text;

  RETURN updated_count;
END;
$function$

