CREATE OR REPLACE FUNCTION public.prune_watch_history()
 RETURNS void
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  user_record RECORD;
  new_history JSONB;
  cutoff_ms BIGINT;
BEGIN
  -- 60 days ago in milliseconds
  cutoff_ms := (EXTRACT(EPOCH FROM NOW()) - (60 * 24 * 60 * 60)) * 1000;

  FOR user_record IN SELECT id, watch_history FROM public.profiles WHERE watch_history IS NOT NULL LOOP
    
    -- Filter items older than 60 days
    SELECT jsonb_object_agg(key, value)
    INTO new_history
    FROM jsonb_each(user_record.watch_history)
    WHERE (value->>'lastUpdated')::bigint >= cutoff_ms;

    -- Update if changed
    IF new_history IS DISTINCT FROM user_record.watch_history THEN
      UPDATE public.profiles
      SET watch_history = COALESCE(new_history, '{}'::jsonb)
      WHERE id = user_record.id;
    END IF;
    
  END LOOP;
END;
$function$

CREATE OR REPLACE FUNCTION public.redeem_guest_access_link(p_token text)
 RETURNS TABLE(profile_id uuid, username text, account_kind text, guest_expires_at timestamp with time zone, guest_link_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  requester_profile public.profiles%ROWTYPE;
  link_record public.guest_access_links%ROWTYPE;
  guest_username text;
  is_anonymous_session boolean := COALESCE((auth.jwt() ->> 'is_anonymous')::boolean, false);
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF trim(COALESCE(p_token, '')) = '' THEN
    RAISE EXCEPTION 'Guest access token is required';
  END IF;

  SELECT *
  INTO link_record
  FROM public.guest_access_links
  WHERE token_hash = md5(trim(p_token))
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Invalid guest access link';
  END IF;

  SELECT *
  INTO requester_profile
  FROM public.profiles
  WHERE id = requester_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Profile not found for current session';
  END IF;

  IF requester_profile.account_kind = 'guest'
     AND requester_profile.guest_link_id = link_record.id THEN
    RETURN QUERY
    SELECT
      requester_profile.id,
      requester_profile.username,
      requester_profile.account_kind,
      requester_profile.guest_expires_at,
      requester_profile.guest_link_id;
    RETURN;
  END IF;

  IF NOT is_anonymous_session THEN
    RAISE EXCEPTION 'Guest links can only be redeemed from a guest session';
  END IF;

  IF link_record.status = 'disabled' THEN
    RAISE EXCEPTION 'This guest access link has been disabled';
  END IF;

  IF link_record.expires_at <= now() THEN
    UPDATE public.guest_access_links
    SET status = 'expired'
    WHERE id = link_record.id
      AND status <> 'expired';

    RAISE EXCEPTION 'This guest access link has expired';
  END IF;

  IF link_record.used_count >= link_record.max_uses THEN
    UPDATE public.guest_access_links
    SET status = 'exhausted'
    WHERE id = link_record.id
      AND status <> 'exhausted';

    RAISE EXCEPTION 'This guest access link has already been used';
  END IF;

  IF requester_profile.guest_secured_at IS NOT NULL THEN
    RAISE EXCEPTION 'This session is already attached to a secured account';
  END IF;

  IF COALESCE(NULLIF(trim(requester_profile.username), ''), '') = '' THEN
    guest_username := public.build_unique_username(
      'guest_' || right(replace(requester_id::text, '-', ''), 8)
    );
  ELSE
    guest_username := requester_profile.username;
  END IF;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET
    username = guest_username,
    avatar_url = COALESCE(NULLIF(avatar_url, ''), 'https://ui-avatars.com/api/?name=Guest&background=27272a&color=ffffff&bold=true'),
    can_stream = true,
    account_kind = 'guest',
    guest_expires_at = link_record.expires_at,
    guest_created_by = link_record.created_by,
    guest_link_id = link_record.id,
    is_guest_hidden = true
  WHERE id = requester_id;

  UPDATE public.guest_access_links
  SET
    used_count = used_count + 1,
    status = CASE
      WHEN used_count + 1 >= max_uses THEN 'exhausted'
      ELSE status
    END
  WHERE id = link_record.id;

  RETURN QUERY
  SELECT
    profile.id,
    profile.username,
    profile.account_kind,
    profile.guest_expires_at,
    profile.guest_link_id
  FROM public.profiles profile
  WHERE profile.id = requester_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.save_recent_search(p_query text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  safe_query text := NULLIF(btrim(COALESCE(p_query, '')), '');
  current_searches jsonb := '[]'::jsonb;
  next_searches jsonb := '[]'::jsonb;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF safe_query IS NULL THEN
    RETURN '[]'::jsonb;
  END IF;

  SELECT COALESCE(recent_searches, '[]'::jsonb)
  INTO current_searches
  FROM public.profiles
  WHERE id = requester_id
  FOR UPDATE;

  WITH cleaned AS (
    SELECT safe_query AS value, 0::bigint AS ord
    UNION ALL
    SELECT btrim(value) AS value, ord
    FROM jsonb_array_elements_text(current_searches) WITH ORDINALITY AS entry(value, ord)
    WHERE NULLIF(btrim(value), '') IS NOT NULL
      AND lower(btrim(value)) <> lower(safe_query)
  ),
  deduped AS (
    SELECT DISTINCT ON (lower(value)) value, ord
    FROM cleaned
    ORDER BY lower(value), ord
  ),
  limited AS (
    SELECT value, ord
    FROM deduped
    ORDER BY ord
    LIMIT 3
  )
  SELECT COALESCE(jsonb_agg(to_jsonb(value) ORDER BY ord), '[]'::jsonb)
  INTO next_searches
  FROM limited;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET recent_searches = next_searches
  WHERE id = requester_id;

  RETURN next_searches;
END;
$function$

CREATE OR REPLACE FUNCTION public.secure_guest_account()
 RETURNS TABLE(profile_id uuid, username text, account_kind text, guest_secured_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  requester_profile public.profiles%ROWTYPE;
  current_email text;
  current_email_confirmed_at timestamptz;
  next_username text;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT *
  INTO requester_profile
  FROM public.profiles
  WHERE id = requester_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Profile not found';
  END IF;

  IF requester_profile.account_kind IS DISTINCT FROM 'guest' THEN
    RAISE EXCEPTION 'Only guest accounts can be secured';
  END IF;

  IF requester_profile.guest_expires_at IS NULL OR requester_profile.guest_expires_at <= now() THEN
    RAISE EXCEPTION 'Guest access has expired';
  END IF;

  SELECT email, email_confirmed_at
  INTO current_email, current_email_confirmed_at
  FROM auth.users
  WHERE id = requester_id;

  IF current_email IS NULL OR trim(current_email) = '' THEN
    RAISE EXCEPTION 'Add an email address before securing this account';
  END IF;

  IF current_email_confirmed_at IS NULL THEN
    RAISE EXCEPTION 'Verify your email before securing this account';
  END IF;

  IF COALESCE(requester_profile.username, '') = ''
     OR requester_profile.username ~ '^guest[_-]'
  THEN
    next_username := public.build_unique_username(split_part(current_email, '@', 1));
  ELSE
    next_username := requester_profile.username;
  END IF;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET
    username = next_username,
    account_kind = 'standard',
    guest_secured_at = now(),
    guest_expires_at = NULL,
    is_guest_hidden = false
  WHERE id = requester_id;

  RETURN QUERY
  SELECT
    profile.id,
    profile.username,
    profile.account_kind,
    profile.guest_secured_at
  FROM public.profiles profile
  WHERE profile.id = requester_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.send_direct_message(p_other_user_id uuid, p_body text DEFAULT NULL::text, p_message_type text DEFAULT 'text'::text, p_shared_movie jsonb DEFAULT NULL::jsonb)
 RETURNS TABLE(id uuid, conversation_id uuid, sender_id uuid, recipient_id uuid, message_type text, body text, shared_movie jsonb, created_at timestamp with time zone, read_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  safe_message_type text := LOWER(NULLIF(btrim(COALESCE(p_message_type, 'text')), ''));
  safe_body text := NULLIF(btrim(COALESCE(p_body, '')), '');
  conversation_record record;
  next_preview text;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF safe_message_type NOT IN ('text', 'movie_share') THEN
    RAISE EXCEPTION 'Invalid message type';
  END IF;

  IF NOT public.are_mutual_followers(requester_id, p_other_user_id) THEN
    RAISE EXCEPTION 'Only mutual followers can message each other';
  END IF;

  IF safe_message_type = 'text' AND safe_body IS NULL THEN
    RAISE EXCEPTION 'Message body is required';
  END IF;

  IF safe_message_type = 'movie_share' AND p_shared_movie IS NULL THEN
    RAISE EXCEPTION 'A shared movie payload is required';
  END IF;

  SELECT *
  INTO conversation_record
  FROM public.get_or_create_direct_conversation(p_other_user_id)
  LIMIT 1;

  next_preview := CASE
    WHEN safe_message_type = 'movie_share' AND safe_body IS NOT NULL THEN LEFT(safe_body, 120)
    WHEN safe_message_type = 'movie_share' THEN 'Shared a title'
    ELSE LEFT(safe_body, 120)
  END;

  UPDATE public.direct_conversations
  SET
    updated_at = now(),
    last_message_at = now(),
    last_message_preview = next_preview,
    last_message_sender_id = requester_id
  WHERE direct_conversations.id = conversation_record.id;

  RETURN QUERY
  INSERT INTO public.direct_messages (
    conversation_id,
    sender_id,
    recipient_id,
    message_type,
    body,
    shared_movie
  )
  VALUES (
    conversation_record.id,
    requester_id,
    p_other_user_id,
    safe_message_type,
    safe_body,
    p_shared_movie
  )
  RETURNING
    direct_messages.id,
    direct_messages.conversation_id,
    direct_messages.sender_id,
    direct_messages.recipient_id,
    direct_messages.message_type,
    direct_messages.body,
    direct_messages.shared_movie,
    direct_messages.created_at,
    direct_messages.read_at;
END;
$function$

