CREATE OR REPLACE FUNCTION public.set_my_recent_searches(p_recent_searches jsonb DEFAULT '[]'::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  normalized_searches jsonb := '[]'::jsonb;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF COALESCE(jsonb_typeof(p_recent_searches), 'null') <> 'array' THEN
    RAISE EXCEPTION 'Recent searches must be a JSON array';
  END IF;

  WITH cleaned AS (
    SELECT btrim(value) AS value, ord
    FROM jsonb_array_elements_text(COALESCE(p_recent_searches, '[]'::jsonb)) WITH ORDINALITY AS entry(value, ord)
    WHERE NULLIF(btrim(value), '') IS NOT NULL
  ),
  deduped AS (
    SELECT DISTINCT ON (lower(value)) value, ord
    FROM cleaned
    ORDER BY lower(value), ord
  ),
  limited AS (
    SELECT value, ord
    FROM deduped
    ORDER BY ord
    LIMIT 3
  )
  SELECT COALESCE(jsonb_agg(to_jsonb(value) ORDER BY ord), '[]'::jsonb)
  INTO normalized_searches
  FROM limited;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET recent_searches = normalized_searches
  WHERE id = requester_id;

  RETURN normalized_searches;
END;
$function$

CREATE OR REPLACE FUNCTION public.submit_request_reply_secure(p_request_id uuid, p_tmdb_id text, p_content text, p_instructions text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, request_id uuid, tmdb_id text, content text, link_type text, instructions text, upvotes integer, created_by uuid, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  safe_tmdb_id text := NULLIF(btrim(COALESCE(p_tmdb_id, '')), '');
  safe_content text := NULLIF(btrim(COALESCE(p_content, '')), '');
  safe_instructions text := NULLIF(btrim(COALESCE(p_instructions, '')), '');
  resolved_link_type text;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Must be logged in to reply';
  END IF;

  IF p_request_id IS NULL OR safe_tmdb_id IS NULL OR safe_content IS NULL THEN
    RAISE EXCEPTION 'A request id, TMDB id, and link are required';
  END IF;

  IF safe_content !~* '^(magnet:|https?://)' THEN
    RAISE EXCEPTION 'Invalid link format. Must be a URL or magnet link.';
  END IF;

  IF length(safe_content) > 2000 THEN
    RAISE EXCEPTION 'Link is too long (max 2000 characters).';
  END IF;

  IF safe_instructions IS NOT NULL AND length(safe_instructions) > 500 THEN
    RAISE EXCEPTION 'Instructions are too long (max 500 characters).';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.movie_requests
    WHERE id = p_request_id
      AND tmdb_id = safe_tmdb_id
  ) THEN
    RAISE EXCEPTION 'Request not found';
  END IF;

  resolved_link_type := CASE
    WHEN safe_content ~* '^magnet:' THEN 'magnet'
    WHEN safe_content ~* 'drive\.google\.com' THEN 'gdrive'
    WHEN safe_content ~* 'mega\.nz' THEN 'mega'
    WHEN safe_content ~* '(youtube\.com|vimeo|\.m3u8)' THEN 'stream'
    ELSE 'other'
  END;

  PERFORM public.enforce_community_rate_limit('submit_reply', 3, 180);

  UPDATE public.movie_requests
  SET status = 'fulfilled', updated_at = now()
  WHERE id = p_request_id;

  RETURN QUERY
  INSERT INTO public.request_replies (
    request_id,
    tmdb_id,
    content,
    link_type,
    instructions,
    created_by
  )
  VALUES (
    p_request_id,
    safe_tmdb_id,
    safe_content,
    resolved_link_type,
    safe_instructions,
    requester_id
  )
  RETURNING
    request_replies.id,
    request_replies.request_id,
    request_replies.tmdb_id,
    request_replies.content,
    request_replies.link_type,
    request_replies.instructions,
    request_replies.upvotes,
    request_replies.created_by,
    request_replies.created_at;
END;
$function$

CREATE OR REPLACE FUNCTION public.track_playlist_view(p_playlist_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  current_analytics jsonb;
  current_week text;
  current_month text;
  stored_week text;
  stored_month text;
  new_analytics jsonb;
  requester_id uuid := auth.uid();
  last_viewer jsonb;
  last_timestamp bigint := 0;
  six_hours_ago bigint := extract(epoch from (now() - interval '6 hours'))::bigint;
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT analytics
  INTO current_analytics
  FROM public.playlists
  WHERE id = p_playlist_id
  FOR UPDATE;

  IF current_analytics IS NULL THEN
    RETURN;
  END IF;

  SELECT viewer
  INTO last_viewer
  FROM jsonb_array_elements(COALESCE(current_analytics->'last_viewers', '[]'::jsonb)) viewer
  WHERE viewer->>'user_id' = requester_id::text
  ORDER BY COALESCE((viewer->>'timestamp')::bigint, 0) DESC
  LIMIT 1;

  IF last_viewer IS NOT NULL THEN
    last_timestamp := COALESCE((last_viewer->>'timestamp')::bigint, 0);
    IF last_timestamp >= six_hours_ago THEN
      RETURN;
    END IF;
  END IF;

  current_week := to_char(now(), 'IYYY-IW');
  current_month := to_char(now(), 'YYYY-MM');
  stored_week := current_analytics->>'week_start';
  stored_month := current_analytics->>'month_start';

  new_analytics := jsonb_build_object(
    'total_views', COALESCE((current_analytics->>'total_views')::int, 0) + 1,
    'weekly_views', CASE WHEN stored_week = current_week THEN COALESCE((current_analytics->>'weekly_views')::int, 0) + 1 ELSE 1 END,
    'monthly_views', CASE WHEN stored_month = current_month THEN COALESCE((current_analytics->>'monthly_views')::int, 0) + 1 ELSE 1 END,
    'week_start', current_week,
    'month_start', current_month,
    'last_viewers', (
      SELECT jsonb_agg(viewer ORDER BY (viewer->>'timestamp')::bigint DESC)
      FROM (
        SELECT viewer
        FROM jsonb_array_elements(COALESCE(current_analytics->'last_viewers', '[]'::jsonb)) viewer
        WHERE viewer->>'user_id' <> requester_id::text
        UNION ALL
        SELECT jsonb_build_object('user_id', requester_id::text, 'timestamp', extract(epoch from now())::bigint)
        LIMIT 10
      ) viewers
    )
  );

  UPDATE public.playlists
  SET analytics = new_analytics
  WHERE id = p_playlist_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.unlike_playlist(p_playlist_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  deleted_count integer := 0;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  DELETE FROM public.playlist_likes
  WHERE user_id = auth.uid()
    AND playlist_id = p_playlist_id;

  GET DIAGNOSTICS deleted_count = ROW_COUNT;

  IF deleted_count > 0 THEN
    UPDATE public.playlists
    SET likes_count = GREATEST(likes_count - 1, 0)
    WHERE id = p_playlist_id;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_my_profile(p_username text DEFAULT NULL::text, p_avatar_url text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, username text, avatar_url text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  requester_id uuid := auth.uid();
  safe_username text := NULLIF(btrim(COALESCE(p_username, '')), '');
  safe_avatar_url text := NULLIF(btrim(COALESCE(p_avatar_url, '')), '');
BEGIN
  IF requester_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF safe_username IS NOT NULL
     AND EXISTS (
       SELECT 1
       FROM public.profiles
       WHERE username = safe_username
         AND id <> requester_id
     )
  THEN
    RAISE EXCEPTION 'Username already taken';
  END IF;

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET
    username = COALESCE(safe_username, username),
    avatar_url = COALESCE(safe_avatar_url, avatar_url)
  WHERE id = requester_id;

  RETURN QUERY
  SELECT profile.id, profile.username, profile.avatar_url
  FROM public.profiles profile
  WHERE profile.id = requester_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.update_watch_history_v2(p_user_id uuid, p_tmdb_id text, p_data jsonb, p_idempotency_key text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  current_history jsonb;
  current_entry jsonb;
  existing_key text;
BEGIN
  IF auth.uid() IS NULL OR auth.uid() <> p_user_id THEN
    RAISE EXCEPTION 'Not authorized to update watch history for this user.';
  END IF;

  SELECT watch_history
  INTO current_history
  FROM public.profiles
  WHERE id = p_user_id;

  IF current_history IS NULL THEN
    current_history := '{}'::jsonb;
  END IF;

  current_entry := COALESCE(current_history->p_tmdb_id, '{}'::jsonb);

  IF p_idempotency_key IS NOT NULL THEN
    existing_key := current_entry->>'idempotencyKey';
    IF existing_key = p_idempotency_key THEN
      RETURN;
    END IF;

    p_data := p_data || jsonb_build_object('idempotencyKey', p_idempotency_key);
  END IF;

  current_history := jsonb_set(current_history, array[p_tmdb_id], p_data, true);

  PERFORM set_config('app.trusted_profile_write', 'on', true);

  UPDATE public.profiles
  SET
    watch_history = current_history,
    last_seen_activity = now()
  WHERE id = p_user_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.upsert_friend_compatibility(p_user_1 uuid, p_user_2 uuid, p_score integer, p_shared_genres jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    u_a UUID;
    u_b UUID;
BEGIN
    -- Ensure consistent ordering to match table constraint
    IF p_user_1 < p_user_2 THEN
        u_a := p_user_1;
        u_b := p_user_2;
    ELSE
        u_a := p_user_2;
        u_b := p_user_1;
    END IF;

    INSERT INTO public.friend_compatibility (user_a, user_b, score, shared_genres, updated_at)
    VALUES (u_a, u_b, p_score, p_shared_genres, NOW())
    ON CONFLICT (user_a, user_b)
    DO UPDATE SET 
        score = EXCLUDED.score,
        shared_genres = EXCLUDED.shared_genres,
        updated_at = NOW();
END;
$function$

CREATE OR REPLACE FUNCTION public.user_can_view_playlist(p_playlist_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id uuid := auth.uid();
  v_is_public boolean;
  v_is_featured boolean;
  v_owner_id uuid;
BEGIN
  SELECT is_public, is_featured, user_id
  INTO v_is_public, v_is_featured, v_owner_id
  FROM public.playlists
  WHERE id = p_playlist_id;

  RETURN (
    v_is_public = true
    OR v_is_featured = true
    OR v_owner_id = v_user_id
    OR public.is_current_user_admin()
    OR public.is_playlist_collaborator(p_playlist_id, v_user_id)
  );
END;
$function$
